    [Fact]    public async Task Test_BinaryLogDownload()
    {
        // Streams binary log segments with control bytes
        var baseUrl = Environment.GetEnvironmentVariable("MOCK_SERVER_URL") ?? "http://localhost:8080";
        using var handler = new System.Net.Http.HttpClientHandler { AllowAutoRedirect = false };
        using var client = new System.Net.Http.HttpClient(handler);
        var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Get, $"{baseUrl}/fixtures/binary_log_download/stream/logfile");
        var response = await client.SendAsync(request);
        Assert.Equal(200, (int)response.StatusCode);
        Assert.True(response.Content.Headers.TryGetValues("content-type", out var hdrcontent_type) && hdrcontent_type.Any(v => v.Contains("application/octet-stream")), "header content-type mismatch");
        var bodyText = await response.Content.ReadAsStringAsync();
        Assert.Equal("LOG:\\u0000\\u0001\\u0002\\u0003|TAIL|\\u0007\\n", bodyText.Trim());
    }

